const economyBySlug: Record<string, EconomyProfile> = {};
for (const profile of economyProfiles) {
  economyBySlug[profile.citySlug] = profile;
}
const jobsBySlug: Record<string, JobsProfile> = {};
for (const profile of jobsProfiles) {
  jobsBySlug[profile.citySlug] = profile;
}

const VALID_ECONOMY_CATEGORIES: ReadonlySet<string> = new Set([
  "global_hub", "major_economy", "regional_center", "industrial_city",
  "tourism_economy", "government_center", "education_research", "mixed",
]);

/** Build-time integrity guard — throws (failing `next build`) on any invalid profile. */
function assertEconomyIntegrity(
  economy: readonly EconomyProfile[],
  jobs: readonly JobsProfile[],
): void {
  const errors: string[] = [];
  const inRange = (n: number) =>
    typeof n === "number" && Number.isFinite(n) && n >= 0 && n <= 100;
  const econSeen = new Set<string>();
  for (const e of economy) {
    if (!e.citySlug) errors.push(`missing citySlug`);
    if (econSeen.has(e.citySlug)) errors.push(`duplicate economy citySlug: ${e.citySlug}`);
    econSeen.add(e.citySlug);
    const scores = [
      e.economyScore, e.employmentScore, e.salaryScore, e.startupScore,
      e.businessEnvironmentScore, e.remoteWorkScore, e.innovationScore,
      e.affordabilityAdjustedIncomeScore,
    ];
    if (scores.some((n) => !inRange(n)))
      errors.push(`${e.citySlug}: economy score out of range`);
    if (e.dominantIndustries.length < 3 || e.dominantIndustries.length > 6)
      errors.push(`${e.citySlug}: dominantIndustries must be 3-6`);
    if (e.dominantIndustries.some((i) => typeof i !== "string" || i.length === 0))
      errors.push(`${e.citySlug}: empty industry`);
    if (!VALID_ECONOMY_CATEGORIES.has(e.economyCategory))
      errors.push(`${e.citySlug}: invalid economyCategory ${e.economyCategory}`);
    const summaries = [
      e.economySummary, e.jobsSummary, e.remoteWorkSummary, e.startupSummary,
    ];
    if (summaries.some((t) => typeof t !== "string" || t.length === 0))
      errors.push(`${e.citySlug}: missing summary`);
  }
  const jobsSeen = new Set<string>();
  for (const jp of jobs) {
    if (jobsSeen.has(jp.citySlug)) errors.push(`duplicate jobs citySlug: ${jp.citySlug}`);
    jobsSeen.add(jp.citySlug);
    const scores = [
      jp.jobMarketScore, jp.technologyJobsScore, jp.healthcareJobsScore,
      jp.financeJobsScore, jp.manufacturingJobsScore, jp.tourismJobsScore,
      jp.educationJobsScore, jp.remoteWorkAvailabilityScore,
      jp.overallCareerOpportunityScore,
    ];
    if (scores.some((n) => !inRange(n)))
      errors.push(`${jp.citySlug}: jobs score out of range`);
  }
  for (const slug of econSeen)
    if (!jobsSeen.has(slug)) errors.push(`${slug}: economy without jobs profile`);
  for (const slug of jobsSeen)
    if (!econSeen.has(slug)) errors.push(`${slug}: jobs without economy profile`);
  if (errors.length > 0) {
    throw new Error(`economy integrity failure:\n${errors.join("\n")}`);
  }
}

assertEconomyIntegrity(economyProfiles, jobsProfiles);

export function getEconomy(citySlug: string): EconomyProfile | undefined {
  return economyBySlug[citySlug];
}

export function hasEconomy(citySlug: string): boolean {
  return Object.prototype.hasOwnProperty.call(economyBySlug, citySlug);
}

export function getAllEconomyProfiles(): readonly EconomyProfile[] {
  return economyProfiles;
}

export function getJobs(citySlug: string): JobsProfile | undefined {
  return jobsBySlug[citySlug];
}

export function hasJobs(citySlug: string): boolean {
  return Object.prototype.hasOwnProperty.call(jobsBySlug, citySlug);
}

export function getAllJobsProfiles(): readonly JobsProfile[] {
  return jobsProfiles;
}
